const headers=$('Webhook Check').first().json.headers||{};const body=$('Webhook Check').first().json.body||{};
const token=(headers.authorization||headers.Authorization||'').replace('Bearer ','');
if(!token) return [{json:{error:true,message:'Thiếu token',status:401}}];
let userId;try{userId=JSON.parse(Buffer.from(token.split('.')[1],'base64').toString()).sub;if(!userId)throw 0;}catch(e){return [{json:{error:true,message:'Token không hợp lệ',status:401}}];}
if(!body.document_text&&!body.protocol_content) return [{json:{error:true,message:'Thiếu nội dung đề cương (document_text)',status:400}}];
const protocolType=body.protocol_type||'iq';
if(!/^[a-z0-9_]{1,30}$/.test(protocolType)) return [{json:{error:true,message:'protocol_type không hợp lệ',status:400}}];
return [{json:{error:false,user_id:userId,document_text:body.document_text||body.protocol_content,protocol_type:protocolType,equipment_code:body.equipment_code||'',template_id:body.template_id||null,document_language:body.document_language||'vi'}}];

