const results=$input.all().map(i=>i.json);
const prev=$('Parse + Auth').first().json;
const roles=results.filter(r=>r.role_name).map(r=>r.role_name);
if(!roles.some(r=>['admin','qa_manager','validation'].includes(r))) return [{json:{error:true,message:'Không có quyền check đề cương',status:403}}];

// Layer 1: Rule-based check (không AI)
const text=prev.document_text;
const ruleFindings=[];
if(!text.match(/mục đích|purpose/i)) ruleFindings.push({severity:'major',layer:'rule_check',location:'Document',finding:'Thiếu mục Mục đích',risk:'Đề cương không rõ mục tiêu',recommendation:'Thêm section Mục đích'});
if(!text.match(/phạm vi|scope/i)) ruleFindings.push({severity:'major',layer:'rule_check',location:'Document',finding:'Thiếu mục Phạm vi',risk:'Không rõ phạm vi áp dụng',recommendation:'Thêm section Phạm vi'});
if(!text.match(/tiêu chí|acceptance|criteria/i)) ruleFindings.push({severity:'critical',layer:'rule_check',location:'Document',finding:'Thiếu tiêu chí chấp nhận',risk:'Không có cơ sở kết luận đạt/không đạt',recommendation:'Thêm tiêu chí chấp nhận có căn cứ'});
if(!text.match(/trách nhiệm|responsibility/i)) ruleFindings.push({severity:'major',layer:'rule_check',location:'Document',finding:'Thiếu mục Trách nhiệm',risk:'Không rõ ai thực hiện',recommendation:'Thêm section Trách nhiệm'});

// Layer 2: Template comparison
const tpl=results.find(r=>r.template_structure);
let templateFindings=[];
if(tpl?.template_structure){
  const sections=typeof tpl.template_structure==='string'?JSON.parse(tpl.template_structure):tpl.template_structure;
  sections.filter(s=>s.required).forEach(s=>{
    if(!text.toLowerCase().includes(s.title.toLowerCase())) templateFindings.push({severity:'major',layer:'template_check',location:s.section,finding:'Thiếu section: '+s.title,risk:'Không đúng template đã duyệt',recommendation:'Thêm section '+s.section+' '+s.title});
  });
}

const prompt=results.find(r=>r.prompt_text);
const docSnippet=text.substring(0,6000);
const messages=[{role:'system',content:prompt?.prompt_text||'Kiểm tra đề cương GMP. Trả JSON tiếng Việt.'},{role:'user',content:'=== ĐỀ CƯƠNG CẦN KIỂM TRA ===\nLoại: '+prev.protocol_type.toUpperCase()+'\nThiết bị: '+prev.equipment_code+'\nNgôn ngữ: '+prev.document_language+'\n\n'+docSnippet+'\n\n=== FINDINGS TỪ RULE-CHECK ===\n'+JSON.stringify(ruleFindings.concat(templateFindings))+'\n\nHãy kiểm tra semantic (Layer 4): nội dung phù hợp thiết bị không, test method hợp lý không, acceptance criteria đo được không. Trả JSON.'}];

return [{json:{...prev,messages,ruleFindings,templateFindings,primary_role:roles[0]}}];

const ai=$input.first().json;
const prev=$('Layer 1-2 Check + Build AI').first().json;
const aiText=ai.choices?.[0]?.message?.content||'{}';
let aiReview={};
try{const cleaned=aiText.replace(/```json|```/g,'').trim();aiReview=JSON.parse(cleaned);}catch(e){aiReview={overall_status:'CONDITIONAL',critical_findings:[],major_findings:[],minor_findings:[]};}

// Merge all findings
const allFindings=[...prev.ruleFindings,...prev.templateFindings,...(aiReview.critical_findings||[]).map(f=>({...f,severity:'critical',layer:'semantic_review'})),...(aiReview.major_findings||[]).map(f=>({...f,severity:'major',layer:'semantic_review'})),...(aiReview.minor_findings||[]).map(f=>({...f,severity:'minor',layer:'semantic_review'}))];

const critical=allFindings.filter(f=>f.severity==='critical').length;
const major=allFindings.filter(f=>f.severity==='major').length;
const minor=allFindings.filter(f=>f.severity==='minor').length;
const status=critical>0?'FAIL':major>2?'CONDITIONAL':'PASS';
const score=Math.max(0,100-critical*25-major*10-minor*3);

const escaped=JSON.stringify(allFindings).replace(/'/g,"''");
const sql=`INSERT INTO protocol_reviews(user_id,protocol_type,equipment_code,document_language,overall_status,overall_score,critical_count,major_count,minor_count,model_used,prompt_version) VALUES('${prev.user_id}'::uuid,'${prev.protocol_type}','${prev.equipment_code}','${prev.document_language}','${status}',${score},${critical},${major},${minor},'gpt-4o-mini','v1.0') RETURNING id;\nSELECT write_audit_log('${prev.user_id}'::uuid,NULL,'${prev.primary_role}','ai_check_protocol'::audit_action,'Check ${prev.protocol_type.toUpperCase()} - ${prev.equipment_code} → ${status}');`;

return [{json:{sql,response:{success:true,overall_status:status,overall_score:score,critical_count:critical,major_count:major,minor_count:minor,findings:allFindings,disclaimer:'⚕ Kết quả kiểm tra do AI thực hiện, cần người có chuyên môn xác nhận.'}}}];
